import	java.util.*;
import	java.io.*;
public	class	Main{
	static	int[]Z=new	int[100];
	static	int	res(Pot2D	P,int	m){
		int	s=0;
		for(;m>P.x;P.y=Math.min(P.y,Z[++P.x]))	++s;
		for(;m<P.x;P.y=Math.min(P.y,Z[--P.x]))	++s;
		return	s;
	}
	public	static	void	main(String[]args)throws	Exception{
		Scanner	fin=new	Scanner(new	File("input.txt"));
		PrintStream	fout=new	PrintStream("output.txt");
		Pot2D	B=new	Pot2D(),E=new	Pot2D(),T=new	Pot2D();
		for(int	s,t,n;fin.hasNextInt();fout.println(s)){
			for(n=fin.nextInt(),s=0;n>s;Z[s++]=fin.nextInt());
			B.x=fin.nextInt()-1;B.y=fin.nextInt()-1;
			E.x=fin.nextInt()-1;E.y=fin.nextInt()-1;
			for(s=999999;0<n--;s=Math.min(s,Math.abs(E.y-T.y)+t)){
				T.x=B.x;T.y=B.y;t=res(T,n);t+=res(T,E.x);
			}
		}
	}
}
class	Pot2D{int	x,y;}
